  ('disabled-c5fb3965-moex-00220', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '警察甲因收受賄款，對駕車超速之乙允諾不予舉發違規通知單，嗣經所屬 警察局政風室接獲檢舉後函送檢察官偵辦，檢察官以甲已認罪並繳交賄 款，而提起公訴，下列關於甲論罪之敘述，何者正確？', '["甲成立違背職務上之行為收受賄賂罪，因已於偵查中自首並繳交所得， 得減輕其刑", "甲成立違背職務上之行為收受賄賂罪，因已於偵查中自白並繳交所得， 應減輕其刑", "甲成立不違背職務上之行為收受賄賂罪，因已於偵查中自首並繳交所 得，得減輕其刑", "甲成立不違背職務上之行為收受賄賂罪，因已於偵查中自白並繳交所 得，應減輕其刑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
